const input = $input.first().json;
const filters = {
  hostname: input.hostname || null,
  filter_by_type: input.filter_by_type || null,
  filter_by_ids: input.filter_by_ids ? JSON.parse(input.filter_by_ids) : null
};
console.log('NetBox-Abfrage: Input Parameters =', JSON.stringify(filters));
if (filters.hostname) {
  console.log(`🎯 Suche nach Hostname: "${filters.hostname}"`);
} else if (filters.filter_by_type) {
  console.log(`🎯 Suche nach Type: "${filters.filter_by_type}"`);
} else if (filters.filter_by_ids) {
  console.log(`🎯 Suche nach IDs: ${JSON.stringify(filters.filter_by_ids)}`);
} else {
  console.log(`📋 Keine Filter - alle Objekte werden zurückgegeben`);
}
return { json: filters };

const items = $input.all();
const filterByType = $('🔧 Parse Input Parameters').first().json.filter_by_type;
const filterByIds = $('🔧 Parse Input Parameters').first().json.filter_by_ids;
const hostname = $('🔧 Parse Input Parameters').first().json.hostname;

let processed = items.map(item => {
  const obj = item.json;
  let ip = null;
  if (obj.primary_ip4 && obj.primary_ip4.address) {
    ip = obj.primary_ip4.address.split('/')[0];
  }

  // Objekte ohne IP werden gefiltert (NetBox Query hat has_primary_ip=true für Devices)
  if (!ip) return null;

  const cf = obj.custom_fields || {};
  const default_user = obj.type === 'device' ? 'admin' : 'root';
  const ssh_user = cf.ssh_username || default_user;
  const ssh_password = cf.ssh_password || null;

  return {
    json: {
      id: obj.id,
      type: obj.type || 'unknown',
      hostname: obj.name,
      ip: ip,
      ssh_user: ssh_user,
      ssh_password: ssh_password
    }
  };
}).filter(item => item !== null);

console.log(`📋 Verarbeitet: ${processed.length} Objekte mit IP`);

let filtered = processed;

// Wenn Hostname gegeben ist: ONLY dieses Objekt zurückgeben
if (hostname) {
  console.log(`🎯 Hostname-Filter aktiv: "${hostname}"`);
  filtered = filtered.filter(item => item.json.hostname === hostname);
  console.log(`✅ Hostname-Filter Ergebnis: ${filtered.length} Objekt(e) gefunden`);
} else {
  // Hostname nicht gegeben: Fallback-Filter anwenden (nur wenn hostname=null)
  if (filterByType) {
    console.log(`🎯 Filter nach Type: "${filterByType}"`);
    filtered = filtered.filter(item => item.json.type === filterByType);
  }
  if (filterByIds && Array.isArray(filterByIds)) {
    console.log(`🎯 Filter nach IDs: ${JSON.stringify(filterByIds)}`);
    filtered = filtered.filter(item => filterByIds.includes(item.json.id));
  }
}

const output = filtered.map(item => ({
  json: {
    hostname: item.json.hostname,
    ip: item.json.ip,
    ssh_user: item.json.ssh_user,
    ssh_password: item.json.ssh_password
  }
}));

console.log(`📊 NetBox-Abfrage: Total zurückgegeben = ${output.length}`);
return output;
